var React = require('react')

var StoryStore = require('./stores/StoryStore').default

var PageNumberMixin = require('./mixins/PageNumberMixin').default
var Paginator = require('./Paginator').default
var Spinner = require('./Spinner').default
var StoryListItem = require('./StoryListItem').default
var SettingsStore = require('./stores/SettingsStore').default

var {ITEMS_PER_PAGE} = require('./utils/constants').default
var pageCalc = require('./utils/pageCalc').default
var setTitle = require('./utils/setTitle').default
var scrollPosition = require('./utils/scrollPosition').default

var Stories = React.createClass({
  mixins: [PageNumberMixin],

  propTypes: {
    // The number of stories which may be paginated through
    limit: React.PropTypes.number.isRequired,
    // The route name being used
    route: React.PropTypes.string.isRequired,
    // The type of stories being displayed
    type: React.PropTypes.string.isRequired,

    // Page title associated with the stories being displayed
    title: React.PropTypes.string
  },

  getInitialState() {
    return {
      ids: null,
      limit: this.props.limit,
      stories: []
    }
  },

  componentDidMount() {
    setTitle(this.props.title)

    // Tell the browser to NOT restore scroll — we handle it ourselves.
    if ('scrollRestoration' in window.history) {
      window.history.scrollRestoration = 'manual'
    }

    this._scrollRestoreKey = this.props.route
    this._paginating = false
    this._cancelScrollRestore = null
    this._newIds = {}

    this.store = new StoryStore(this.props.type)
    this.store.addListener('update', this.handleUpdate)
    this.store.start()
    this.setState(this.store.getState())

    // Capture which item the user clicked so we can restore to it
    this._handleItemClick = function(e) {
      var link = e.target
      while (link && link.tagName !== 'A') {
        link = link.parentElement
      }
      if (link && link.href) {
        var match = link.pathname.match(/^\/(?:item|story|poll|job)\/(\d+)/)
        if (match) {
          scrollPosition.savePosition(this._scrollRestoreKey, match[1])
        }
      }
    }.bind(this)
    document.addEventListener('click', this._handleItemClick, true)

    // Save on page unload (external navigation, refresh)
    this._saveScrollPosition = function() {
      if (!this._paginating) {
        scrollPosition.savePosition(this._scrollRestoreKey)
      }
    }.bind(this)
    window.addEventListener('beforeunload', this._saveScrollPosition)
    window.addEventListener('pagehide', this._saveScrollPosition)

    // Debounced scroll save
    this._scrollSaveTimer = null
    this._handleScroll = function() {
      clearTimeout(this._scrollSaveTimer)
      this._scrollSaveTimer = setTimeout(function() {
        if (!this._paginating) {
          scrollPosition.savePosition(this._scrollRestoreKey)
        }
      }.bind(this), 500)
    }.bind(this)
    window.addEventListener('scroll', this._handleScroll, {passive: true})
  },

  componentDidUpdate() {
    // Compensate scroll when new items are prepended from background fetch
    if (this._compensateScroll > 0) {
      var newIds = Object.keys(this._newIds)
      if (newIds.length > 0) {
        var totalHeight = 0
        for (var i = 0; i < newIds.length; i++) {
          var el = document.querySelector('.ListItem[data-id="' + newIds[i] + '"]')
          if (el) {
            totalHeight += el.offsetHeight
          }
        }
        if (totalHeight > 0) {
          window.scrollTo(0, this._compensateScroll + totalHeight)
        }
      }
      this._compensateScroll = 0
    }
  },

  componentWillUnmount() {
    if (this._cancelScrollRestore) {
      this._cancelScrollRestore()
      this._cancelScrollRestore = null
    }

    clearTimeout(this._scrollSaveTimer)

    // Save scroll position when leaving (unless paginating or already saved via click)
    this._saveScrollPosition()

    document.removeEventListener('click', this._handleItemClick, true)
    window.removeEventListener('beforeunload', this._saveScrollPosition)
    window.removeEventListener('pagehide', this._saveScrollPosition)
    window.removeEventListener('scroll', this._handleScroll)
    this.store.removeListener('update', this.handleUpdate)
    this.store.stop()
    this.store = null
  },

  /**
   * Called by Paginator before it clears the scroll position.
   * Prevents componentWillUnmount from re-saving the stale position.
   */
  _onPageChange() {
    this._paginating = true
    // Cancel any pending restore from the old page
    if (this._cancelScrollRestore) {
      this._cancelScrollRestore()
      this._cancelScrollRestore = null
    }
  },

  handleUpdate(update) {
    if (!this.isMounted()) {
      if (process.env.NODE_ENV !== 'production') {
        console.warn(
          `Skipping update as the ${this.props.type} Stories component is no longer mounted.`
        )
      }
      return
    }

    // Detect newly arrived items for entrance animation and scroll compensation
    var prevIds = this.state.ids
    if (prevIds && update.ids) {
      var prevSet = {}
      for (var j = 0; j < prevIds.length; j++) {
        prevSet[prevIds[j]] = true
      }
      for (var k = 0; k < update.ids.length; k++) {
        if (!prevSet[update.ids[k]]) {
          this._newIds[update.ids[k]] = true
        }
      }
    }

    // Save scroll position before setState so we can compensate after render.
    // Only when user is scrolled down — if at top, new items won't shift anything.
    var currentScroll = window.pageYOffset || document.documentElement.scrollTop
    this._compensateScroll = (currentScroll > 0 && Object.keys(this._newIds).length > 0)
      ? currentScroll
      : 0

    update.limit = update.ids.length
    this.setState(update)

    // Restore scroll position when items first arrive from Firebase
    if (!this._scrollRestoreTriggered && update.ids && update.ids.length > 0) {
      this._scrollRestoreTriggered = true
      this._cancelScrollRestore = scrollPosition.restorePosition(this._scrollRestoreKey)
    }
  },

  /**
   * Called by StoryListItem after its entrance animation completes.
   */
  _onItemEntered(id) {
    delete this._newIds[id]
  },

  render() {
    var page = pageCalc(this.getPageNumber(), ITEMS_PER_PAGE, this.state.limit)

    // Special case for the Read Stories page, as its ids are read from
    // localStorage and there might not be any yet.
    if (this.props.type === 'read') {
      if (this.state.ids == null) {
        return <div className="Items"></div>
      }
      if (this.state.ids.length === 0) {
        return <div className="Items">
          <p>There are no previously read stories to display.</p>
        </div>
      }
    }

    // Display a list of placeholder items while we're waiting for the initial
    // list of story ids to load from Firebase.
    if (this.state.ids == null) {
      var dummyItems = []
      for (var i = page.startIndex; i < page.endIndex; i++) {
        dummyItems.push(
          <li key={i} className="ListItem ListItem--loading" style={{marginBottom: SettingsStore.listSpacing}}>
            <Spinner/>
          </li>
        )
      }
      return <div className="Items Items--loading">
        <ol className="Items__list" start={page.startIndex + 1}>{dummyItems}</ol>
        <Paginator route={this.props.route} page={page.pageNum} hasNext={page.hasNext} onPageChange={this._onPageChange}/>
      </div>
    }

    return <div className="Items">
      <ol className="Items__list" start={page.startIndex + 1}>
        {this.renderItems(page.startIndex, page.endIndex)}
      </ol>
      <Paginator route={this.props.route} page={page.pageNum} hasNext={page.hasNext} onPageChange={this._onPageChange}/>
    </div>
  },

  renderItems(startIndex, endIndex) {
    var rendered = []
    for (var i = startIndex; i < endIndex; i++) {
      var item = this.state.stories[i]
      var id = this.state.ids[i]
      if (id) {
        var isNew = !!this._newIds[id]
        rendered.push(<StoryListItem key={id} id={id} index={i} cachedItem={item} store={this.store} isNew={isNew} onEntered={this._onItemEntered}/>)
      }
      else {
        rendered.push(<StoryListItem key={i} cachedItem={item} store={this.store}/>)
      }
    }
    return rendered
  }
})

export default Stories
