/**
 * Scroll position manager: saves the topmost visible item ID,
 * restores by scrolling that item into view.
 */
var STORAGE_KEY = 'react-hn-scroll'

function escapeSelector(str) {
  if (typeof CSS !== 'undefined' && CSS.escape) {
    return CSS.escape(str)
  }
  return String(str).replace(/[\\'"[\]]/g, '\\$&')
}

/**
 * Get the ID of the ListItem closest to the viewport center.
 */
function getCenterVisibleItemId() {
  var items = document.querySelectorAll('.ListItem[data-id]')
  var centerY = window.innerHeight / 2
  var bestId = null
  var bestDist = Infinity
  for (var i = 0; i < items.length; i++) {
    var rect = items[i].getBoundingClientRect()
    if (rect.bottom <= 0 || rect.top >= window.innerHeight) continue
    var itemCenter = (rect.top + rect.bottom) / 2
    var dist = Math.abs(itemCenter - centerY)
    if (dist < bestDist) {
      bestDist = dist
      bestId = items[i].getAttribute('data-id')
    }
  }
  return bestId
}

/**
 * Save an item ID (or find the center-visible one).
 */
function savePosition(routeKey, itemId) {
  if (!itemId) {
    itemId = getCenterVisibleItemId()
  }
  if (!itemId) return
  try {
    window.sessionStorage.setItem(STORAGE_KEY + ':' + routeKey, itemId)
  } catch (e) {}
}

/**
 * Restore scroll position by finding the saved item and scrolling it into view.
 * @returns {Function} cancel function
 */
function restorePosition(routeKey) {
  var cancelled = false
  var highlightTimer = null

  function cancel() {
    cancelled = true
    if (highlightTimer) {
      clearTimeout(highlightTimer)
      highlightTimer = null
    }
  }

  var itemId
  try {
    itemId = window.sessionStorage.getItem(STORAGE_KEY + ':' + routeKey)
  } catch (e) {
    return cancel
  }
  if (!itemId) return cancel

  // Clear immediately so a page refresh doesn't replay it
  clearPosition(routeKey)

  var escaped = escapeSelector(itemId)
  var attempts = 0

  function doRestore() {
    if (cancelled) return

    var el = document.querySelector('.ListItem[data-id="' + escaped + '"]')
    if (el) {
      // Use getBoundingClientRect + scrollTo — scrollIntoView is unreliable on iOS
      var rect = el.getBoundingClientRect()
      var currentScroll = window.pageYOffset || document.documentElement.scrollTop || 0
      var targetY = currentScroll + rect.top - 6
      if (targetY < 0) targetY = 0
      window.scrollTo(0, targetY)
      document.documentElement.scrollTop = targetY
      document.body.scrollTop = targetY

      el.classList.add('ListItem--scroll-restore')
      highlightTimer = setTimeout(function() {
        if (!cancelled) {
          el.classList.remove('ListItem--scroll-restore')
        }
      }, 2500)
      return
    }

    // Item not in DOM yet, retry
    attempts++
    if (attempts < 40) {
      setTimeout(doRestore, 80)
    }
  }

  // Double rAF: first waits for React render, second for browser layout
  requestAnimationFrame(function() {
    requestAnimationFrame(function() {
      if (!cancelled) doRestore()
    })
  })

  return cancel
}

function clearPosition(routeKey) {
  try {
    window.sessionStorage.removeItem(STORAGE_KEY + ':' + routeKey)
  } catch (e) {}
}

export default {
  savePosition,
  restorePosition,
  clearPosition
}
